import{_ as r,c as o,o as l,ag as a}from"./chunks/framework.DK1-H3E1.js";const p=JSON.parse('{"title":"编码器-解码器结构（Encoder-Decoder）入门","description":"","frontmatter":{"order":14},"headers":[],"relativePath":"ai/encoder-decoder-architecture.md","filePath":"ai/encoder-decoder-architecture.md","lastUpdated":1772197851000}'),i={name:"ai/encoder-decoder-architecture.md"};function t(n,e,d,c,s,h){return l(),o("div",null,e[0]||(e[0]=[a('<h1 id="编码器-解码器结构-encoder-decoder-入门" tabindex="-1">编码器-解码器结构（Encoder-Decoder）入门 <a class="header-anchor" href="#编码器-解码器结构-encoder-decoder-入门" aria-label="Permalink to &quot;编码器-解码器结构（Encoder-Decoder）入门&quot;">​</a></h1><blockquote><p>📅 主题：Transformer 中 Encoder-Decoder 的职责分工与工作流程</p></blockquote><h2 id="一、什么是编码器-解码器结构" tabindex="-1">一、什么是编码器-解码器结构 <a class="header-anchor" href="#一、什么是编码器-解码器结构" aria-label="Permalink to &quot;一、什么是编码器-解码器结构&quot;">​</a></h2><p><strong>编码器-解码器（Encoder-Decoder）</strong> 是一种经典的序列建模架构，核心思想是：</p><ol><li><strong>编码器（Encoder）</strong> 先把输入序列编码成上下文表示；</li><li><strong>解码器（Decoder）</strong> 再基于这些表示一步步生成输出序列。</li></ol><p>可以把它理解为：</p><ul><li>编码器负责“读懂输入”</li><li>解码器负责“按目标格式写出输出”</li></ul><p>在机器翻译、摘要、问答生成、语音转文本等任务中都非常常见。</p><hr><h2 id="二、为什么需要这种分工" tabindex="-1">二、为什么需要这种分工 <a class="header-anchor" href="#二、为什么需要这种分工" aria-label="Permalink to &quot;二、为什么需要这种分工&quot;">​</a></h2><p>对很多任务来说，输入和输出并不是同一种文本形式，例如：</p><ul><li>翻译：中文输入 → 英文输出</li><li>摘要：长文输入 → 短摘要输出</li><li>对话：用户问题输入 → 回复输出</li></ul><p>编码器-解码器结构的优势是：</p><ul><li><strong>输入理解和输出生成解耦</strong>：职责清晰</li><li><strong>便于跨模态/跨语言</strong>：输入输出空间可不同</li><li><strong>可控生成过程</strong>：解码器按 token 逐步生成，支持长度控制、采样策略</li></ul><hr><h2 id="三、transformer-中的-encoder-与-decoder" tabindex="-1">三、Transformer 中的 Encoder 与 Decoder <a class="header-anchor" href="#三、transformer-中的-encoder-与-decoder" aria-label="Permalink to &quot;三、Transformer 中的 Encoder 与 Decoder&quot;">​</a></h2><p>在 Transformer 里，这个架构被标准化成两套堆叠模块。</p><h2 id="_3-1-encoder-编码器" tabindex="-1">3.1 Encoder（编码器） <a class="header-anchor" href="#_3-1-encoder-编码器" aria-label="Permalink to &quot;3.1 Encoder（编码器）&quot;">​</a></h2><p>每层一般包含：</p><ol><li><strong>多头自注意力（Multi-Head Self-Attention）</strong></li><li><strong>前馈网络（Feed Forward Network）</strong></li><li>残差连接 + LayerNorm</li></ol><p>编码器输入是整段源序列（可并行处理），输出是每个位置的上下文化向量表示。</p><h2 id="_3-2-decoder-解码器" tabindex="-1">3.2 Decoder（解码器） <a class="header-anchor" href="#_3-2-decoder-解码器" aria-label="Permalink to &quot;3.2 Decoder（解码器）&quot;">​</a></h2><p>每层一般包含：</p><ol><li><strong>掩码自注意力（Masked Self-Attention）</strong></li><li><strong>交叉注意力（Cross-Attention）</strong></li><li><strong>前馈网络（FFN）</strong></li><li>残差连接 + LayerNorm</li></ol><p>其中关键是：</p><ul><li><strong>掩码自注意力</strong>：只能看见已生成内容，不能偷看未来 token</li><li><strong>交叉注意力</strong>：让解码器在生成时读取编码器输出（即“对输入对齐”）</li></ul><hr><h2 id="四、工作流程-以翻译为例" tabindex="-1">四、工作流程（以翻译为例） <a class="header-anchor" href="#四、工作流程-以翻译为例" aria-label="Permalink to &quot;四、工作流程（以翻译为例）&quot;">​</a></h2><p>假设任务：把 <code>我喜欢机器学习</code> 翻译成英文。</p><ol><li>输入句子进入 Encoder，得到上下文表示 <code>H</code></li><li>Decoder 从起始标记 <code>&lt;BOS&gt;</code> 开始</li><li>第一步预测第一个词（如 <code>I</code>）</li><li>将 <code>I</code> 作为下一步输入，继续预测 <code>like</code></li><li>重复直到生成结束标记 <code>&lt;EOS&gt;</code></li></ol><p>每一步预测都依赖：</p><ul><li>已生成的历史 token（Masked Self-Attention）</li><li>编码器输出 <code>H</code>（Cross-Attention）</li></ul><p>这就是标准的自回归生成流程。</p><hr><h2 id="五、掩码与交叉注意力为什么关键" tabindex="-1">五、掩码与交叉注意力为什么关键 <a class="header-anchor" href="#五、掩码与交叉注意力为什么关键" aria-label="Permalink to &quot;五、掩码与交叉注意力为什么关键&quot;">​</a></h2><h2 id="_5-1-掩码-causal-mask" tabindex="-1">5.1 掩码（Causal Mask） <a class="header-anchor" href="#_5-1-掩码-causal-mask" aria-label="Permalink to &quot;5.1 掩码（Causal Mask）&quot;">​</a></h2><p>如果不加掩码，训练时 Decoder 会看到“未来正确答案”，推理时却看不到，造成训练-推理不一致。<br> 掩码保证它始终只能基于过去位置预测当前 token，和推理阶段一致。</p><h2 id="_5-2-交叉注意力-cross-attention" tabindex="-1">5.2 交叉注意力（Cross-Attention） <a class="header-anchor" href="#_5-2-交叉注意力-cross-attention" aria-label="Permalink to &quot;5.2 交叉注意力（Cross-Attention）&quot;">​</a></h2><p>仅靠 Decoder 自注意力会让生成更像“续写”。<br> 交叉注意力让解码器对齐输入内容，确保输出真正基于源信息，而不是自由发挥。</p><hr><h2 id="六、与三类主流-llm-架构的关系" tabindex="-1">六、与三类主流 LLM 架构的关系 <a class="header-anchor" href="#六、与三类主流-llm-架构的关系" aria-label="Permalink to &quot;六、与三类主流 LLM 架构的关系&quot;">​</a></h2><p>当前常见模型大致分三类：</p><ol><li><strong>Encoder-only（如 BERT）</strong><ul><li>更擅长理解任务（分类、检索、表示学习）</li></ul></li><li><strong>Decoder-only（如 GPT）</strong><ul><li>更擅长生成任务（续写、对话、代码生成）</li></ul></li><li><strong>Encoder-Decoder（如 T5、BART）</strong><ul><li>天然适合“输入到输出”的 Seq2Seq 任务（翻译、摘要、改写）</li></ul></li></ol><p>这也是为什么不同模型在不同任务上表现风格不同。</p><hr><h2 id="七、工程视角-优缺点" tabindex="-1">七、工程视角：优缺点 <a class="header-anchor" href="#七、工程视角-优缺点" aria-label="Permalink to &quot;七、工程视角：优缺点&quot;">​</a></h2><h3 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to &quot;优点&quot;">​</a></h3><ul><li>输入输出分工明确，适配通用序列转换任务</li><li>交叉注意力可显式“读输入”，对齐性好</li><li>对结构化生成任务（如模板化输出）常更稳定</li></ul><h3 id="挑战" tabindex="-1">挑战 <a class="header-anchor" href="#挑战" aria-label="Permalink to &quot;挑战&quot;">​</a></h3><ul><li>计算开销较大（两套堆叠 + 交叉注意力）</li><li>训练和部署复杂度高于纯 Decoder 架构</li><li>在超长上下文场景下，需要额外优化策略</li></ul><hr><h2 id="八、在应用开发中的启示" tabindex="-1">八、在应用开发中的启示 <a class="header-anchor" href="#八、在应用开发中的启示" aria-label="Permalink to &quot;八、在应用开发中的启示&quot;">​</a></h2><p>即使你不直接训练模型，理解 Encoder-Decoder 也有帮助：</p><ol><li><strong>模型选型</strong>：翻译/摘要等 seq2seq 任务可优先考虑此类架构</li><li><strong>任务设计</strong>：明确输入与输出边界，便于模型“先理解再生成”</li><li><strong>效果解释</strong>：当输出偏离输入时，往往与“输入信息对齐不足”有关</li><li><strong>RAG 配合</strong>：检索片段相当于强化输入侧语义，帮助 Decoder 生成更稳</li></ol><hr><h2 id="九、小结" tabindex="-1">九、小结 <a class="header-anchor" href="#九、小结" aria-label="Permalink to &quot;九、小结&quot;">​</a></h2><ol><li>编码器-解码器结构通过“先编码输入、再条件生成输出”解决序列转换任务。</li><li>Encoder 负责理解上下文，Decoder 负责逐步生成。</li><li>Decoder 中的掩码自注意力保证自回归一致性，交叉注意力保证对输入对齐。</li><li>与 Encoder-only、Decoder-only 相比，Encoder-Decoder 在翻译、摘要等任务上更天然。</li><li>理解该结构有助于模型选型、系统设计与生成质量分析。</li></ol><p>掌握编码器-解码器结构，你就完成了 Transformer 核心模块的关键拼图。</p>',58)]))}const g=r(i,[["render",t]]);export{p as __pageData,g as default};
